import subprocess, json, re, urllib.request

# Read .env
with open('expo/.env') as f:
    lines = f.readlines()

env = {}
for line in lines:
    line = line.strip()
    if '=' in line and not line.startswith('#'):
        key, val = line.split('=', 1)
        env[key] = val

gh_token = env.get('GITHUB_TOKEN', '')
render_key_raw = env.get('RENDER_API_KEY', '')
match = re.search(r'rnd_[a-zA-Z0-9]+', render_key_raw)
render_key = match.group(0) if match else ''

# Test GitHub
def github_req(path):
    req = urllib.request.Request(f'https://api.github.com{path}')
    req.add_header('Authorization', f'Bearer {gh_token}')
    req.add_header('Accept', 'application/vnd.github+json')
    req.add_header('User-Agent', 'rork-deploy')
    try:
        resp = urllib.request.urlopen(req)
        return resp.status, resp.read().decode()
    except urllib.error.HTTPError as e:
        return e.code, e.read().decode()

# Test repo access
status, body = github_req('/repos/ibb142/rork-global-real-estate-invest')
d = json.loads(body) if body else {}
print(f"GITHUB REPO: {status}")
print(f"  full_name: {d.get('full_name')}")
print(f"  default_branch: {d.get('default_branch')}")
print(f"  permissions: {d.get('permissions')}")

# Test branch
status, body = github_req('/repos/ibb142/rork-global-real-estate-invest/branches/main')
d = json.loads(body) if body else {}
print(f"GITHUB BRANCH: {status}")
print(f"  sha: {d.get('commit', {}).get('sha', 'N/A')}")

# Test Render
def render_req(path):
    req = urllib.request.Request(f'https://api.render.com/v1{path}')
    req.add_header('Authorization', f'Bearer {render_key}')
    req.add_header('Accept', 'application/json')
    try:
        resp = urllib.request.urlopen(req)
        return resp.status, resp.read().decode()
    except urllib.error.HTTPError as e:
        return e.code, e.read().decode()

status, body = render_req('/services?limit=20')
print(f"\nRENDER SERVICES: {status}")
if status == 200:
    services = json.loads(body)
    for s in services:
        print(f"  {s.get('name')} | id={s.get('id')} | repo={s.get('repo')} | autoDeploy={s.get('autoDeploy')}")
else:
    print(f"  ERROR: {body[:500]}")
PYEOF

