import json, re, urllib.request, urllib.error, base64, hashlib

with open('expo/.env') as f:
    lines = f.readlines()
env = {}
for line in lines:
    line = line.strip()
    if '=' in line and not line.startswith('#'):
        key, val = line.split('=', 1)
        env[key] = val

gh_token = env.get('GITHUB_TOKEN', '')

def github_req(method, path, body=None):
    url = f'https://api.github.com{path}'
    data = json.dumps(body).encode() if body else None
    req = urllib.request.Request(url, data=data, method=method)
    req.add_header('Authorization', f'Bearer {gh_token}')
    req.add_header('Accept', 'application/vnd.github+json')
    req.add_header('User-Agent', 'rork-deploy')
    if data:
        req.add_header('Content-Type', 'application/json')
    try:
        resp = urllib.request.urlopen(req)
        return resp.status, json.loads(resp.read().decode())
    except urllib.error.HTTPError as e:
        return e.code, json.loads(e.read().decode())

repo = 'ibb142/rork-global-real-estate-invest'

# Test 1: Create a test blob
test_content = "test write access"
blob_body = {"content": base64.b64encode(test_content.encode()).decode(), "encoding": "base64"}
status, result = github_req('POST', f'/repos/{repo}/git/blobs', blob_body)
print(f"BLOB CREATE: {status}")
if status == 201:
    print(f"  blob sha: {result.get('sha')}")
elif status == 403:
    print(f"  ERROR: {result.get('message')}")
elif status == 422:
    print(f"  VALIDATION: {result.get('message')}")
else:
    print(f"  {json.dumps(result)[:300]}")

# Test 2: Get the latest commit to get tree sha
status, branch = github_req('GET', f'/repos/{repo}/git/ref/heads/main')
print(f"\nREF GET: {status}")
latest_sha = branch.get('object', {}).get('sha', '')
print(f"  latest commit: {latest_sha}")

status, commit = github_req('GET', f'/repos/{repo}/git/commits/{latest_sha}')
print(f"\nCOMMIT GET: {status}")
tree_sha = commit.get('tree', {}).get('sha', '')
print(f"  tree sha: {tree_sha}")

# Test 3: Try creating a tree
test_tree = {
    "base_tree": tree_sha,
    "tree": [{"path": "test-write.txt", "mode": "100644", "type": "blob", "content": "test"}]
}
status, result = github_req('POST', f'/repos/{repo}/git/trees', test_tree)
print(f"\nTREE CREATE: {status}")
if status == 201:
    print(f"  tree sha: {result.get('sha')}")
else:
    print(f"  {json.dumps(result)[:500]}")
PYEOF

